import java.util.HashMap;
import java.util.Map;

public class Solution {
    public static long solve(long[] nums, long k) {
        long current_sum = 0;
        long dp = 0;
        Map<Long, Long> map = new HashMap<>();
        map.put(0, 0L);
        for (long num : nums) {
            current_sum += num;
            long remainder = current_sum % k;
            long max_val = map.getOrDefault(remainder, Long.MIN_VALUE);
            long candidate = max_val + current_sum;
            long new_dp = Math.max(dp, candidate);
            long current_value = new_dp - current_sum;
            if (map.containsKey(remainder)) {
                if (current_value > map.get(remainder)) {
                    map.put(remainder, current_value);
                }
            } else {
                map.put(remainder, current_value);
            }
            dp = new_dp;
        }
        return current_sum - dp;
    }
}
