    long prefix_sum = 0;
    long[] max_mod = new long[(int) k];
    for (int i = 0; i < k; i++) {
        max_mod[i] = Long.MIN_VALUE;
    }
    max_mod[0] = 0;
    long dp_prev = 0;
    for (long num : nums) {
        prefix_sum += num;
        int current_mod = (int) (prefix_sum % k);
        long candidate = Long.MIN_VALUE;
        if (max_mod[current_mod] != Long.MIN_VALUE) {
            candidate = max_mod[current_mod] + prefix_sum;
        }
        long dp_current = Math.max(dp_prev, candidate);
        long new_val = dp_current - prefix_sum;
        if (new_val > max_mod[current_mod]) {
            max_mod[current_mod] = new_val;
        }
        dp_prev = dp_current;
    }
    long total_sum = prefix_sum;
    return total_sum - dp_prev;
}
